import{c as s,Q as i,j as n,m as e}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"包名、Bundle ID、版本号与构建号","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/03-包名BundleID版本号与构建号.md","filePath":"mobileCommonLearning/03-包名BundleID版本号与构建号.md","lastUpdated":1780912084000}'),p={name:"mobileCommonLearning/03-包名BundleID版本号与构建号.md"};function t(l,a,d,o,r,c){return i(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="包名、bundle-id、版本号与构建号" tabindex="-1">包名、Bundle ID、版本号与构建号 <a class="header-anchor" href="#包名、bundle-id、版本号与构建号" aria-label="Permalink to &quot;包名、Bundle ID、版本号与构建号&quot;">​</a></h1><p>移动端最不能乱改的东西,不是应用名和图标,而是应用身份和版本身份。</p><p>一句话先记住:<strong>包名 / Bundle ID 决定是不是同一个 App,版本号 / 构建号决定能不能更新。</strong></p><hr><h2 id="一、android-applicationid" tabindex="-1">一、Android applicationId <a class="header-anchor" href="#一、android-applicationid" aria-label="Permalink to &quot;一、Android applicationId&quot;">​</a></h2><p>Android 线上身份看 <code>applicationId</code>:</p><div class="language-kotlin vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">kotlin</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">android</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    defaultConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        applicationId </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;com.example.app&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        versionCode </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 42</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        versionName </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;1.3.0&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>applicationId</code> 一旦上线,不要改。</p><p>改了就变成另一个 App:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>com.example.app      旧 App</span></span>
<span class="line"><span>com.example.app.new  新 App</span></span></code></pre></div><p>用户无法覆盖升级,商店也会按新应用处理。</p><hr><h2 id="二、ios-bundle-id" tabindex="-1">二、iOS Bundle ID <a class="header-anchor" href="#二、ios-bundle-id" aria-label="Permalink to &quot;二、iOS Bundle ID&quot;">​</a></h2><p>iOS 线上身份看 Bundle Identifier:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>com.example.app</span></span></code></pre></div><p>它绑定:</p><ul><li>Apple Developer 后台的 App ID</li><li>App Store Connect 的 App</li><li>Provisioning Profile</li><li>entitlements</li><li>推送、App Groups、Associated Domains 等能力</li></ul><p>Bundle ID 改了,基本就是新 App。</p><hr><h2 id="三、包名和展示名不是一回事" tabindex="-1">三、包名和展示名不是一回事 <a class="header-anchor" href="#三、包名和展示名不是一回事" aria-label="Permalink to &quot;三、包名和展示名不是一回事&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>能否改</th><th>影响</th></tr></thead><tbody><tr><td>应用展示名</td><td>可以</td><td>用户看到的名称</td></tr><tr><td>图标</td><td>可以</td><td>用户看到的图标</td></tr><tr><td>Android applicationId</td><td>上线后不要改</td><td>应用身份</td></tr><tr><td>iOS Bundle ID</td><td>上线后不要改</td><td>应用身份</td></tr><tr><td>Android namespace</td><td>可调整</td><td>代码 / R 类命名空间</td></tr><tr><td>iOS Product Name</td><td>可调整</td><td>构建产物名</td></tr></tbody></table><p>不要因为改品牌名就顺手改包名。</p><hr><h2 id="四、android-versioncode-versionname" tabindex="-1">四、Android versionCode / versionName <a class="header-anchor" href="#四、android-versioncode-versionname" aria-label="Permalink to &quot;四、Android versionCode / versionName&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>versionCode  给系统和商店比较大小,必须递增</span></span>
<span class="line"><span>versionName  给用户看,可以是 1.2.3</span></span></code></pre></div><p>例子:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>versionName = 1.4.0</span></span>
<span class="line"><span>versionCode = 104000</span></span></code></pre></div><p>规则可以设计成:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>major * 100000 + minor * 1000 + patch * 10 + build</span></span></code></pre></div><p>但最重要的是:<strong>永远递增</strong>。</p><hr><h2 id="五、ios-version-build" tabindex="-1">五、iOS version / build <a class="header-anchor" href="#五、ios-version-build" aria-label="Permalink to &quot;五、iOS version / build&quot;">​</a></h2><p>iOS 有两个值:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CFBundleShortVersionString  用户看到的版本,如 1.4.0</span></span>
<span class="line"><span>CFBundleVersion             build number,每次上传要递增</span></span></code></pre></div><p>同一个 version 可以有多个 build:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1.4.0 (101)</span></span>
<span class="line"><span>1.4.0 (102)</span></span>
<span class="line"><span>1.4.0 (103)</span></span></code></pre></div><p>TestFlight 常见做法是 build 递增,正式版再提升 version。</p><hr><h2 id="六、多端版本规则" tabindex="-1">六、多端版本规则 <a class="header-anchor" href="#六、多端版本规则" aria-label="Permalink to &quot;六、多端版本规则&quot;">​</a></h2><p>不要让 Android 和 iOS 完全自由发挥。</p><p>推荐:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>产品版本:1.8.0</span></span>
<span class="line"><span>Android versionName:1.8.0</span></span>
<span class="line"><span>iOS version:1.8.0</span></span>
<span class="line"><span>Android versionCode:自动递增</span></span>
<span class="line"><span>iOS build:自动递增</span></span></code></pre></div><p>内部记录:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>release 1.8.0</span></span>
<span class="line"><span>  Android versionCode 108023</span></span>
<span class="line"><span>  iOS build 230</span></span>
<span class="line"><span>  commit abc1234</span></span></code></pre></div><p>发版后要能追溯到 commit。</p><hr><h2 id="七、多环境身份" tabindex="-1">七、多环境身份 <a class="header-anchor" href="#七、多环境身份" aria-label="Permalink to &quot;七、多环境身份&quot;">​</a></h2><p>开发、预发、生产建议用不同身份:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Android:</span></span>
<span class="line"><span>  com.example.app.dev</span></span>
<span class="line"><span>  com.example.app.staging</span></span>
<span class="line"><span>  com.example.app</span></span>
<span class="line"><span></span></span>
<span class="line"><span>iOS:</span></span>
<span class="line"><span>  com.example.app.dev</span></span>
<span class="line"><span>  com.example.app.staging</span></span>
<span class="line"><span>  com.example.app</span></span></code></pre></div><p>好处:</p><ul><li>可同时安装</li><li>推送证书 / token 不混</li><li>三方登录白名单不混</li><li>测试不会误打生产</li></ul><p>代价:</p><ul><li>每个环境都要配置推送、深链、登录、支付等能力</li><li>iOS 每个 Bundle ID 都要 App ID / profile</li></ul><hr><h2 id="八、三方平台白名单" tabindex="-1">八、三方平台白名单 <a class="header-anchor" href="#八、三方平台白名单" aria-label="Permalink to &quot;八、三方平台白名单&quot;">​</a></h2><p>这些平台经常绑定包名和签名指纹:</p><ul><li>微信登录 / 支付</li><li>支付宝</li><li>Google Sign-In</li><li>Firebase</li><li>华为 / 小米 / OPPO / vivo 推送</li><li>地图 SDK</li><li>广告归因</li><li>App Links / Universal Links</li></ul><p>换包名或换签名后,要同步所有平台。</p><p>这就是为什么包身份和签名不能随便动。</p><hr><h2 id="九、什么时候会出事故" tabindex="-1">九、什么时候会出事故 <a class="header-anchor" href="#九、什么时候会出事故" aria-label="Permalink to &quot;九、什么时候会出事故&quot;">​</a></h2><ol><li>改公司名时顺手改了包名,老用户不能升级。</li><li>iOS build 没递增,App Store Connect 拒收。</li><li>Android versionCode 比线上低,渠道拒收。</li><li>dev / prod 用同一个包名,测试包覆盖了正式包。</li><li>换签名后微信登录失败,因为开放平台指纹没更新。</li><li>App Links 使用旧签名指纹,线上深链失效。</li></ol><hr><h2 id="十、检查清单" tabindex="-1">十、检查清单 <a class="header-anchor" href="#十、检查清单" aria-label="Permalink to &quot;十、检查清单&quot;">​</a></h2><ul><li>[ ] applicationId / Bundle ID 是否最终确定</li><li>[ ] 是否区分 dev / staging / prod</li><li>[ ] versionCode / build 是否自动递增</li><li>[ ] 版本号是否能追溯到 commit</li><li>[ ] 三方平台白名单是否记录包名和指纹</li><li>[ ] App Links / Universal Links 是否按环境配置</li><li>[ ] 渠道包是否能区分版本和渠道</li></ul><hr><h2 id="十一、心智模型" tabindex="-1">十一、心智模型 <a class="header-anchor" href="#十一、心智模型" aria-label="Permalink to &quot;十一、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用身份:applicationId / Bundle ID</span></span>
<span class="line"><span>签名身份:keystore / certificate</span></span>
<span class="line"><span>版本身份:versionCode / build number</span></span>
<span class="line"><span>能力身份:entitlements / fingerprints / platform config</span></span></code></pre></div><p>这些身份稳定,发版才稳定。</p><p>下一篇 04 讲移动端打包与签名管理。</p>`,70)])])}const b=s(p,[["render",t]]);export{u as __pageData,b as default};
